public mutating func update(_ header: HTTPHeader) {
    guard let index = headers.index(of: header.name) else {
        headers.append(header)
        return
    }

    headers.replaceSubrange(index...index, with: [header])
}

@resultBuilder
    struct DisposableBuilder {
        public static func buildBlock(_ disposables: Disposable...) -> [Disposable] {
            disposables
        }
    }

public func isCached(forKey key: String) -> Bool {
    guard let _ = value(forKey: key, extendingExpiration: .none) else {
        return false
    }
    return true
}

switch playbackState {
case .playing, nil:
  timeOffset = 0
case .paused(let frame):
  timeOffset = animation.time(forFrame: frame)
}

internal init(_ combinations: CombinationsSequence) {
  self.base = combinations.base
  self.kRange = combinations.kRange ?? 0..<0
  self.indexes = Array(combinations.base.indices.prefix(kRange.lowerBound))
}

if keyframes.count == 1 {
  return singleKeyframeAnimation(
    for: property,
    keyframeValue: try keyframeValueMapping(keyframes[0].value),
    writeDirectlyToPropertyIfPossible: true
  )
}

if context.mustUseComplexTimeRemapping {
  return try defaultAnimation(
    for: property,
    keyframes: Keyframes.manuallyInterpolatedWithTimeRemapping(keyframeGroup, context: context),
    value: keyframeValueMapping,
    context: context.withoutTimeRemapping()
  )
}

guard
      let customizableProperty = property.customizableProperty,
      let customKeyframes = try context.valueProviderStore.customKeyframes(
        of: customizableProperty,
        for: AnimationKeypath(keys: context.currentKeypath.keys + customizableProperty.name.map { $0.rawValue }),
        context: context
      )
    else { return nil }

if isFirstSegment {
  segmentStartTime = min(
    try context.time(forFrame: context.animation.startFrame),
    segmentStartTime
  )
}

if isLastSegment {
  segmentEndTime = max(
    try context.time(forFrame: context.animation.endFrame),
    segmentEndTime
  )
}

if let cornerRadius = pathKeyframe.cornerRadius {
  path = path.roundCorners(radius: cornerRadius.cgFloatValue)
}

guard
      let cornerRadius,
      cornerRadius.keyframes.contains(where: { $0.value.cgFloatValue > 0 })
    else {
      return path.map { path in
        BezierPathKeyframe(path: path, cornerRadius: nil)
      }
    }

switch gradient.gradientType {
case .linear:
  try addLinearGradientAnimations(for: gradient, context: context)
case .radial:
  try addRadialGradientAnimations(for: gradient, context: context)
case .none:
  break
}

if let strokeColor = stroke.strokeColor {
  try addAnimation(
    for: .strokeColor,
    keyframes: strokeColor,
    value: \.cgColorValue,
    context: context
  )
}

guard bounds.width > 0, bounds.height > 0 else {
  context.logger.assertionFailure("Size must be non-zero before an animation can be played")
  return .zero
}

switch mode {
case .abort:
  throw CompatibilityTracker.Error.encounteredCompatibilityIssue(issue)
case .track:
  issues.append(issue)
}

guard let typedLayer = layer as? Self else {
  fatalError("init(layer:) incorrectly called with \(type(of: layer))")
}

if isAnimationPlaying == true {
  lottieAnimationLayer?.updateInFlightAnimation()
} else {
  let currentFrame = currentFrame
  removeAnimations()
  self.currentFrame = currentFrame
}

for sublayer in allSublayers {
  if let imageLayer = sublayer as? ImageLayer {
    imageLayer.setupImage(context: layerContext)
  }
}

for sublayer in allSublayers {
  if let textLayer = sublayer as? TextLayer {
    try? textLayer.configureRenderLayer(with: layerContext)
  }
}

guard server.info.version >= .canNavigateThroughFrontend else {
    Current.Log.warning("Cannot navigate through frontend, core version is too low")
    completion(false)
    return
}

if let overlayedController {
    overlayedController.present(controller, animated: animated, completion: nil)
} else {
    present(controller, animated: animated, completion: nil)
}

if let api = Current.api(for: server) {
    api.connection.disconnect()
    api.connection.connect()
}

if !Current.isCatalyst {
    // refreshing is handled by menu/keyboard shortcuts
    refreshControl.addTarget(self, action: #selector(pullToRefresh(_:)), for: .valueChanged)
    webView.scrollView.addSubview(refreshControl)
    webView.scrollView.bounces = true
}

if let statusBarButtonsStack {
    statusBarButtonsStack.removeFromSuperview()
    self.statusBarButtonsStack = nil
}

if let selectedText = result as? String, !selectedText.isEmpty {
    // Copy to clipboard
    UIPasteboard.general.string = selectedText
}

if navigationAction.targetFrame == nil {
    guard let url = navigationAction.request.url else {
        Current.Log.error("Received navigation action without URL for new window")
        return nil
    }
    openURLInBrowser(url, self)
}

if #available(iOS 17.0, *) {
    let viewModel = DownloadManagerViewModel()
    let downloadManager = DownloadManagerView(viewModel: viewModel)
    let downloadController = UIHostingController(rootView: downloadManager)
    presentOverlayController(controller: downloadController, animated: true)
    download.delegate = viewModel
}

guard let node = notification.userInfo?["NSObject"] as? Node,
			let containerID = (node.representedObject as? ContainerIdentifiable)?.containerID else {
			return
		}
